//! Q4_K mat-vec via bit-plane dilation + LUT ("dilate the dimensionality first").
//!
//! Each Q4_K weight is affine in its 4-bit nibble: `w = (d·sc)·q + (−dmin·m)`,
//! with one `(sc, m)` per 32-element sub-block.  So a row dot product is
//!   `Σ_sub [ A_sub · Σ_{c∈sub} q_c x_c  +  B_sub · Σ_{c∈sub} x_c ]`,
//! and the nibble term `Σ q_c x_c` is computed by LIFTING each nibble into its 4
//! binary bit-planes (the dilation): each plane's contribution is a subset-sum of
//! `x` that a small lookup table replaces, then we fold back `Σ_j 2^j planeⱼ`.
//! `Σ_{c∈sub} x_c` is independent of the row → precomputed once.
//!
//! Weights are repacked OFFLINE into bit-plane group masks (same 4-bit footprint).
//! The scalar path here is the correctness reference; the NEON path (vqtbl,
//! 16 rows/instruction) is gated below.  Validated against `math::mat_vec_q4k`.

use crate::math::{f16_to_f32, get_scale_min_k4_pub};

/// 4 activations per LUT group → 16-entry table.
const GROUP: usize = 4;
const GROUPS_PER_SUB: usize = 32 / GROUP; // 8
const PLANES: usize = 4;

/// Offline-repacked Q4_K weights: per-sub-block affine scales + bit-plane masks.
pub struct Q4kBitplanes {
    pub n: usize,
    pub d: usize,
    subs_per_row: usize, // d / 32
    /// `A[r*subs + s] = d_val * sc` (the multiplicative scale).
    a: Vec<f32>,
    /// `B[r*subs + s] = -dmin * m` (the additive min).
    b: Vec<f32>,
    /// `masks[((r*subs + s)*PLANES + plane)*GROUPS_PER_SUB + g]` ∈ 0..15.
    masks: Vec<u8>,
}

/// Extract the 4-bit nibble of global element `s_local*32 + e` from a block's qs.
#[inline]
fn nibble(qs: &[u8], s_local: usize, e: usize) -> u8 {
    let byte = qs[(s_local >> 1) * 32 + e];
    if s_local & 1 == 0 {
        byte & 0x0f
    } else {
        byte >> 4
    }
}

/// Repack raw Q4_K weight bytes into bit-plane form (offline, one-time).
pub fn q4k_to_bitplanes(w: &[u8], n: usize, d: usize) -> Q4kBitplanes {
    let bpr = d / 256;
    let subs_per_row = d / 32;
    let mut a = vec![0.0f32; n * subs_per_row];
    let mut b = vec![0.0f32; n * subs_per_row];
    let mut masks = vec![0u8; n * subs_per_row * PLANES * GROUPS_PER_SUB];

    for r in 0..n {
        for blk in 0..bpr {
            let bp = &w[(r * bpr + blk) * 144..(r * bpr + blk + 1) * 144];
            let d_val = f16_to_f32(u16::from_le_bytes([bp[0], bp[1]]));
            let dmin = f16_to_f32(u16::from_le_bytes([bp[2], bp[3]]));
            let scales = &bp[4..16];
            let qs = &bp[16..144];
            for s_local in 0..8 {
                let s = blk * 8 + s_local;
                let (sc, m) = get_scale_min_k4_pub(s_local, scales);
                a[r * subs_per_row + s] = d_val * sc;
                b[r * subs_per_row + s] = -dmin * m;
                for g in 0..GROUPS_PER_SUB {
                    for plane in 0..PLANES {
                        let mut mask = 0u8;
                        for i in 0..GROUP {
                            let q = nibble(qs, s_local, g * GROUP + i);
                            mask |= ((q >> plane) & 1) << i;
                        }
                        let idx = ((r * subs_per_row + s) * PLANES + plane) * GROUPS_PER_SUB + g;
                        masks[idx] = mask;
                    }
                }
            }
        }
    }
    Q4kBitplanes { n, d, subs_per_row, a, b, masks }
}

/// Scalar reference LUT mat-vec (exact float LUT — validates the decomposition).
pub fn mat_vec_q4k_lut_scalar(out: &mut [f32], x: &[f32], bp: &Q4kBitplanes) {
    let subs = bp.subs_per_row;
    // per-sub x-LUT (16 entries/group) + Sx_sub, built once, reused over all rows.
    let mut lut = vec![0.0f32; subs * GROUPS_PER_SUB * 16];
    let mut sx = vec![0.0f32; subs];
    for s in 0..subs {
        let mut tot = 0.0f32;
        for g in 0..GROUPS_PER_SUB {
            let base = &x[s * 32 + g * GROUP..s * 32 + g * GROUP + GROUP];
            let o = &mut lut[(s * GROUPS_PER_SUB + g) * 16..(s * GROUPS_PER_SUB + g) * 16 + 16];
            o[0] = 0.0;
            for mm in 1..16usize {
                let low = mm.trailing_zeros() as usize;
                o[mm] = o[mm & (mm - 1)] + base[low];
            }
            tot += base.iter().sum::<f32>();
        }
        sx[s] = tot;
    }

    for r in 0..bp.n {
        let mut acc = 0.0f32;
        for s in 0..subs {
            let mut qdot = 0.0f32;
            for plane in 0..PLANES {
                let mut sp = 0.0f32;
                for g in 0..GROUPS_PER_SUB {
                    let idx = ((r * subs + s) * PLANES + plane) * GROUPS_PER_SUB + g;
                    sp += lut[(s * GROUPS_PER_SUB + g) * 16 + bp.masks[idx] as usize];
                }
                qdot += ((1u32 << plane) as f32) * sp;
            }
            acc += bp.a[r * subs + s] * qdot + bp.b[r * subs + s] * sx[s];
        }
        out[r] = acc;
    }
}

/// Block-repacked Q4_K: 16 rows blocked contiguously for SIMD table lookup
/// (`vqtbl1q` on aarch64, `i8x16.swizzle` on wasm32). Requires `n % 16 == 0`.
///   a/b[(blk*subs + s)*16 + rib]
///   masks[(((blk*subs + s)*PLANES + plane)*GROUPS_PER_SUB + g)*16 + rib]
#[cfg(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64"))]
pub struct Q4kBitplanesNeon {
    pub n: usize,
    pub d: usize,
    subs: usize,
    a: Vec<f32>,
    b: Vec<f32>,
    masks: Vec<u8>,
}

#[cfg(any(target_arch = "aarch64", target_arch = "wasm32", target_arch = "x86_64"))]
pub fn q4k_to_bitplanes_neon(w: &[u8], n: usize, d: usize) -> Q4kBitplanesNeon {
    assert!(n.is_multiple_of(16), "NEON LUT path requires n % 16 == 0 (got {n})");
    let bpr = d / 256;
    let subs = d / 32;
    let blocks16 = n / 16;
    let mut a = vec![0.0f32; blocks16 * subs * 16];
    let mut b = vec![0.0f32; blocks16 * subs * 16];
    let mut masks = vec![0u8; blocks16 * subs * PLANES * GROUPS_PER_SUB * 16];
    for r in 0..n {
        let blk = r / 16;
        let rib = r % 16;
        for blkk in 0..bpr {
            let bp = &w[(r * bpr + blkk) * 144..(r * bpr + blkk + 1) * 144];
            let d_val = f16_to_f32(u16::from_le_bytes([bp[0], bp[1]]));
            let dmin = f16_to_f32(u16::from_le_bytes([bp[2], bp[3]]));
            let scales = &bp[4..16];
            let qs = &bp[16..144];
            for s_local in 0..8 {
                let s = blkk * 8 + s_local;
                let (sc, m) = get_scale_min_k4_pub(s_local, scales);
                a[(blk * subs + s) * 16 + rib] = d_val * sc;
                b[(blk * subs + s) * 16 + rib] = -dmin * m;
                for g in 0..GROUPS_PER_SUB {
                    for plane in 0..PLANES {
                        let mut mask = 0u8;
                        for i in 0..GROUP {
                            let q = nibble(qs, s_local, g * GROUP + i);
                            mask |= ((q >> plane) & 1) << i;
                        }
                        let idx = (((blk * subs + s) * PLANES + plane) * GROUPS_PER_SUB + g) * 16 + rib;
                        masks[idx] = mask;
                    }
                }
            }
        }
    }
    Q4kBitplanesNeon { n, d, subs, a, b, masks }
}

/// NEON LUT mat-vec: per-sub int8 activation quant (±31, single table), `vqtbl1q`
/// resolves 16 output rows per instruction; per-row affine scales applied after.
/// Parallel over 16-row blocks (matches production's rayon path for a fair bench).
#[cfg(target_arch = "aarch64")]
pub fn mat_vec_q4k_lut_neon(out: &mut [f32], x: &[f32], bp: &Q4kBitplanesNeon) {
    use gnosis_frf::prelude::*;
    let subs = bp.subs;
    // per-sub: int8 LUT (16/group), quant scale sxq, and Sx (float sum). Built once.
    let mut lut = vec![0i8; subs * GROUPS_PER_SUB * 16];
    let mut sxq = vec![0.0f32; subs];
    let mut sx = vec![0.0f32; subs];
    for s in 0..subs {
        let seg = &x[s * 32..s * 32 + 32];
        let mx = seg.iter().fold(0.0f32, |a, &v| a.max(v.abs()));
        let scale = if mx > 0.0 { mx / 31.0 } else { 1.0 };
        sxq[s] = scale;
        sx[s] = seg.iter().sum();
        for g in 0..GROUPS_PER_SUB {
            let base = &seg[g * GROUP..g * GROUP + GROUP];
            let o = &mut lut[(s * GROUPS_PER_SUB + g) * 16..(s * GROUPS_PER_SUB + g) * 16 + 16];
            for mm in 0..16usize {
                let mut acc = 0i32;
                for i in 0..GROUP {
                    if (mm >> i) & 1 == 1 {
                        acc += (base[i] / scale).round().clamp(-31.0, 31.0) as i32;
                    }
                }
                o[mm] = acc as i8;
            }
        }
    }

    out.par_chunks_mut(16).enumerate().for_each(|(blk, chunk)| {
        unsafe { lut_block_neon(chunk, bp, &lut, &sxq, &sx, blk, subs) }
    });
}

#[cfg(target_arch = "aarch64")]
#[inline]
unsafe fn lut_block_neon(
    chunk: &mut [f32],
    bp: &Q4kBitplanesNeon,
    lut: &[i8],
    sxq: &[f32],
    sx: &[f32],
    blk: usize,
    subs: usize,
) {
    use std::arch::aarch64::*;
    let mut yacc = [vdupq_n_f32(0.0); 4];
    for s in 0..subs {
        let mut p = [[vdupq_n_s32(0); 4]; PLANES];
        for plane in 0..PLANES {
            for g in 0..GROUPS_PER_SUB {
                let tbl = vld1q_s8(lut.as_ptr().add((s * GROUPS_PER_SUB + g) * 16));
                let mbase = (((blk * subs + s) * PLANES + plane) * GROUPS_PER_SUB + g) * 16;
                let idx = vld1q_u8(bp.masks.as_ptr().add(mbase));
                let v = vqtbl1q_s8(tbl, idx);
                let lo16 = vmovl_s8(vget_low_s8(v));
                let hi16 = vmovl_s8(vget_high_s8(v));
                p[plane][0] = vaddq_s32(p[plane][0], vmovl_s16(vget_low_s16(lo16)));
                p[plane][1] = vaddq_s32(p[plane][1], vmovl_s16(vget_high_s16(lo16)));
                p[plane][2] = vaddq_s32(p[plane][2], vmovl_s16(vget_low_s16(hi16)));
                p[plane][3] = vaddq_s32(p[plane][3], vmovl_s16(vget_high_s16(hi16)));
            }
        }
        let sxq_s = sxq[s];
        let sx_s = sx[s];
        for q in 0..4 {
            let qd = vaddq_s32(
                vaddq_s32(p[0][q], vshlq_n_s32(p[1][q], 1)),
                vaddq_s32(vshlq_n_s32(p[2][q], 2), vshlq_n_s32(p[3][q], 3)),
            );
            let qd_f = vmulq_n_f32(vcvtq_f32_s32(qd), sxq_s);
            let a16 = vld1q_f32(bp.a.as_ptr().add((blk * subs + s) * 16 + q * 4));
            let b16 = vld1q_f32(bp.b.as_ptr().add((blk * subs + s) * 16 + q * 4));
            yacc[q] = vfmaq_f32(yacc[q], a16, qd_f);
            yacc[q] = vfmaq_n_f32(yacc[q], b16, sx_s);
        }
    }
    for q in 0..4 {
        vst1q_f32(chunk.as_mut_ptr().add(q * 4), yacc[q]);
    }
}

/// wasm32 SIMD LUT mat-vec — same algorithm as `mat_vec_q4k_lut_neon`, using
/// `i8x16_swizzle` (the wasm equivalent of `vqtbl1q`/`vpshufb`) for the 16-row
/// table lookup. Single-threaded (wasm has no threads by default). Browser/edge
/// inference path. Structurally identical to the NEON kernel validated at 2.7e-7.
#[cfg(target_arch = "wasm32")]
pub fn mat_vec_q4k_lut_wasm(out: &mut [f32], x: &[f32], bp: &Q4kBitplanesNeon) {
    use std::arch::wasm32::*;
    let subs = bp.subs;
    let mut lut = vec![0i8; subs * GROUPS_PER_SUB * 16];
    let mut sxq = vec![0.0f32; subs];
    let mut sx = vec![0.0f32; subs];
    for s in 0..subs {
        let seg = &x[s * 32..s * 32 + 32];
        let mx = seg.iter().fold(0.0f32, |a, &v| a.max(v.abs()));
        let scale = if mx > 0.0 { mx / 31.0 } else { 1.0 };
        sxq[s] = scale;
        sx[s] = seg.iter().sum();
        for g in 0..GROUPS_PER_SUB {
            let base = &seg[g * GROUP..g * GROUP + GROUP];
            let o = &mut lut[(s * GROUPS_PER_SUB + g) * 16..(s * GROUPS_PER_SUB + g) * 16 + 16];
            for mm in 0..16usize {
                let mut acc = 0i32;
                for i in 0..GROUP {
                    if (mm >> i) & 1 == 1 {
                        acc += (base[i] / scale).round().clamp(-31.0, 31.0) as i32;
                    }
                }
                o[mm] = acc as i8;
            }
        }
    }

    let blocks16 = bp.n / 16;
    for blk in 0..blocks16 {
        let mut yacc = [f32x4_splat(0.0); 4];
        for s in 0..subs {
            let mut p = [[i32x4_splat(0); 4]; PLANES];
            for plane in 0..PLANES {
                for g in 0..GROUPS_PER_SUB {
                    let tbl = unsafe { v128_load(lut.as_ptr().add((s * GROUPS_PER_SUB + g) * 16) as *const v128) };
                    let mbase = (((blk * subs + s) * PLANES + plane) * GROUPS_PER_SUB + g) * 16;
                    let idx = unsafe { v128_load(bp.masks.as_ptr().add(mbase) as *const v128) };
                    let v = i8x16_swizzle(tbl, idx);
                    let lo16 = i16x8_extend_low_i8x16(v);
                    let hi16 = i16x8_extend_high_i8x16(v);
                    p[plane][0] = i32x4_add(p[plane][0], i32x4_extend_low_i16x8(lo16));
                    p[plane][1] = i32x4_add(p[plane][1], i32x4_extend_high_i16x8(lo16));
                    p[plane][2] = i32x4_add(p[plane][2], i32x4_extend_low_i16x8(hi16));
                    p[plane][3] = i32x4_add(p[plane][3], i32x4_extend_high_i16x8(hi16));
                }
            }
            let sxq_v = f32x4_splat(sxq[s]);
            let sx_v = f32x4_splat(sx[s]);
            for q in 0..4 {
                let qd = i32x4_add(
                    i32x4_add(p[0][q], i32x4_shl(p[1][q], 1)),
                    i32x4_add(i32x4_shl(p[2][q], 2), i32x4_shl(p[3][q], 3)),
                );
                let qd_f = f32x4_mul(f32x4_convert_i32x4(qd), sxq_v);
                let a16 = unsafe { v128_load(bp.a.as_ptr().add((blk * subs + s) * 16 + q * 4) as *const v128) };
                let b16 = unsafe { v128_load(bp.b.as_ptr().add((blk * subs + s) * 16 + q * 4) as *const v128) };
                yacc[q] = f32x4_add(yacc[q], f32x4_mul(a16, qd_f));
                yacc[q] = f32x4_add(yacc[q], f32x4_mul(b16, sx_v));
            }
        }
        for q in 0..4 {
            unsafe { v128_store(out.as_mut_ptr().add(blk * 16 + q * 4) as *mut v128, yacc[q]) };
        }
    }
}

/// x86-64 AVX2 LUT mat-vec — `_mm256_shuffle_epi8`/`_mm_shuffle_epi8` is the x86
/// twin of NEON `vqtbl1q`. Mirrors `mat_vec_q4k_lut_neon` bit-for-bit (16-row
/// blocks, int8 act quant, per-sub affine). This is the path that runs on L4
/// Cloud Run (x86) single-token decode, where the GEMV falls back to the CPU.
#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2,fma")]
unsafe fn lut_block_avx2(
    chunk: &mut [f32],
    bp: &Q4kBitplanesNeon,
    lut: &[i8],
    sxq: &[f32],
    sx: &[f32],
    blk: usize,
    subs: usize,
) {
    use std::arch::x86_64::*;
    let mut yacc = [_mm256_setzero_ps(); 2]; // 16 rows = 2 × 8 f32
    for s in 0..subs {
        let mut p = [[_mm256_setzero_si256(); 2]; PLANES];
        for plane in 0..PLANES {
            for g in 0..GROUPS_PER_SUB {
                let tbl = _mm_loadu_si128(lut.as_ptr().add((s * GROUPS_PER_SUB + g) * 16) as *const __m128i);
                let mbase = (((blk * subs + s) * PLANES + plane) * GROUPS_PER_SUB + g) * 16;
                let idx = _mm_loadu_si128(bp.masks.as_ptr().add(mbase) as *const __m128i);
                let v = _mm_shuffle_epi8(tbl, idx); // 16 int8 results (masks are 0..15)
                let lo8 = _mm256_cvtepi8_epi32(v); // rows 0..7  (sign-extended)
                let hi8 = _mm256_cvtepi8_epi32(_mm_srli_si128(v, 8)); // rows 8..15
                p[plane][0] = _mm256_add_epi32(p[plane][0], lo8);
                p[plane][1] = _mm256_add_epi32(p[plane][1], hi8);
            }
        }
        let sxq_s = _mm256_set1_ps(sxq[s]);
        let sx_s = _mm256_set1_ps(sx[s]);
        for half in 0..2 {
            let qd = _mm256_add_epi32(
                _mm256_add_epi32(p[0][half], _mm256_slli_epi32(p[1][half], 1)),
                _mm256_add_epi32(_mm256_slli_epi32(p[2][half], 2), _mm256_slli_epi32(p[3][half], 3)),
            );
            let qd_f = _mm256_mul_ps(_mm256_cvtepi32_ps(qd), sxq_s);
            let a16 = _mm256_loadu_ps(bp.a.as_ptr().add((blk * subs + s) * 16 + half * 8));
            let b16 = _mm256_loadu_ps(bp.b.as_ptr().add((blk * subs + s) * 16 + half * 8));
            yacc[half] = _mm256_fmadd_ps(a16, qd_f, yacc[half]);
            yacc[half] = _mm256_fmadd_ps(b16, sx_s, yacc[half]);
        }
    }
    _mm256_storeu_ps(chunk.as_mut_ptr(), yacc[0]);
    _mm256_storeu_ps(chunk.as_mut_ptr().add(8), yacc[1]);
}

#[cfg(target_arch = "x86_64")]
pub fn mat_vec_q4k_lut_avx2(out: &mut [f32], x: &[f32], bp: &Q4kBitplanesNeon) {
    use gnosis_frf::prelude::*;
    let subs = bp.subs;
    let mut lut = vec![0i8; subs * GROUPS_PER_SUB * 16];
    let mut sxq = vec![0.0f32; subs];
    let mut sx = vec![0.0f32; subs];
    for s in 0..subs {
        let seg = &x[s * 32..s * 32 + 32];
        let mx = seg.iter().fold(0.0f32, |a, &v| a.max(v.abs()));
        let scale = if mx > 0.0 { mx / 31.0 } else { 1.0 };
        sxq[s] = scale;
        sx[s] = seg.iter().sum();
        for g in 0..GROUPS_PER_SUB {
            let base = &seg[g * GROUP..g * GROUP + GROUP];
            let o = &mut lut[(s * GROUPS_PER_SUB + g) * 16..(s * GROUPS_PER_SUB + g) * 16 + 16];
            for mm in 0..16usize {
                let mut acc = 0i32;
                for i in 0..GROUP {
                    if (mm >> i) & 1 == 1 {
                        acc += (base[i] / scale).round().clamp(-31.0, 31.0) as i32;
                    }
                }
                o[mm] = acc as i8;
            }
        }
    }
    out.par_chunks_mut(16).enumerate().for_each(|(blk, chunk)| unsafe {
        lut_block_avx2(chunk, bp, &lut, &sxq, &sx, blk, subs)
    });
}

// ── Cached dispatch: prepack each weight once, reuse the LUT every decode step ──
//
// Opt-in via `Q4K_LUT=1` (the int8 activation quant carries ~1.8% rel-L2, so it
// stays OFF by default until a perplexity eval). On aarch64 with `rows % 16 == 0`
// it prepacks the weight (keyed by ptr+shape) on first call and serves the LUT
// kernel thereafter; otherwise it returns false and the caller falls back to the
// original `mat_vec_q4k`.

fn q4k_lut_enabled() -> bool {
    use std::sync::OnceLock;
    static EN: OnceLock<bool> = OnceLock::new();
    *EN.get_or_init(|| {
        std::env::var("Q4K_LUT")
            .map(|v| v == "1" || v == "true" || v == "on")
            .unwrap_or(false)
    })
}

#[cfg(any(target_arch = "aarch64", target_arch = "x86_64"))]
fn q4k_lut_cache(
) -> &'static std::sync::Mutex<std::collections::HashMap<(usize, usize, usize), std::sync::Arc<Q4kBitplanesNeon>>>
{
    use std::sync::OnceLock;
    static C: OnceLock<
        std::sync::Mutex<
            std::collections::HashMap<(usize, usize, usize), std::sync::Arc<Q4kBitplanesNeon>>,
        >,
    > = OnceLock::new();
    C.get_or_init(|| std::sync::Mutex::new(std::collections::HashMap::new()))
}

/// Try the cached LUT path for a single-token Q4_K mat-vec. Returns true if it
/// handled the call (LUT), false if the caller should fall back to `mat_vec_q4k`.
#[cfg(any(target_arch = "aarch64", target_arch = "x86_64"))]
pub fn mat_vec_q4k_auto(out: &mut [f32], x: &[f32], w: &[u8], rows: usize, cols: usize) -> bool {
    if !q4k_lut_enabled() || !rows.is_multiple_of(16) {
        return false;
    }
    #[cfg(target_arch = "x86_64")]
    {
        if !std::is_x86_feature_detected!("avx2") || !std::is_x86_feature_detected!("fma") {
            return false;
        }
    }
    let key = (w.as_ptr() as usize, rows, cols);
    let bp = {
        let mut c = q4k_lut_cache().lock().unwrap();
        c.entry(key)
            .or_insert_with(|| std::sync::Arc::new(q4k_to_bitplanes_neon(w, rows, cols)))
            .clone()
    };
    #[cfg(target_arch = "aarch64")]
    mat_vec_q4k_lut_neon(out, x, &bp);
    #[cfg(target_arch = "x86_64")]
    mat_vec_q4k_lut_avx2(out, x, &bp);
    true
}

#[cfg(not(any(target_arch = "aarch64", target_arch = "x86_64")))]
pub fn mat_vec_q4k_auto(_o: &mut [f32], _x: &[f32], _w: &[u8], _r: usize, _c: usize) -> bool {
    false
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::math::mat_vec_q4k;

    fn random_q4k(n: usize, d: usize, seed: u64) -> Vec<u8> {
        let bpr = d / 256;
        let mut s = seed;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut w = vec![0u8; n * bpr * 144];
        for r in 0..n {
            for blk in 0..bpr {
                let off = (r * bpr + blk) * 144;
                // d_val, dmin as small positive f16 (0x2e66 ≈ 0.1, 0x2266 ≈ 0.02)
                w[off..off + 2].copy_from_slice(&0x2e66u16.to_le_bytes());
                w[off + 2..off + 4].copy_from_slice(&0x2266u16.to_le_bytes());
                for k in 4..144 {
                    w[off + k] = (rng() & 0xff) as u8;
                }
            }
        }
        w
    }

    #[test]
    fn lut_scalar_matches_production_q4k() {
        let (n, d) = (512usize, 1024usize);
        let w = random_q4k(n, d, 0xabcdef);
        let mut s = 0x1234u64;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let x: Vec<f32> = (0..d).map(|_| (rng() as i32 as f32) / (i32::MAX as f32)).collect();

        let mut y_ref = vec![0.0f32; n];
        mat_vec_q4k(&mut y_ref, &x, &w, n, d);

        let bp = q4k_to_bitplanes(&w, n, d);
        let mut y_lut = vec![0.0f32; n];
        mat_vec_q4k_lut_scalar(&mut y_lut, &x, &bp);

        let (mut num, mut den) = (0.0f64, 0.0f64);
        for r in 0..n {
            let a = y_ref[r] as f64;
            num += (a - y_lut[r] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!("[q4k-lut] rel-L2 vs production mat_vec_q4k = {rel:.2e}  (rows {n}, d {d})");
        assert!(rel < 1e-4, "scalar float-LUT must match production: rel={rel:.3e}");
    }

    #[cfg(target_arch = "aarch64")]
    #[test]
    fn lut_neon_matches_and_times() {
        use std::time::Instant;
        let (n, d) = (4096usize, 4096usize);
        let w = random_q4k(n, d, 0xfeed);
        let mut s = 0x99u64;
        let mut rng = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let x: Vec<f32> = (0..d).map(|_| (rng() as i32 as f32) / (i32::MAX as f32)).collect();
        let reps = 30u128;

        let mut y_ref = vec![0.0f32; n];
        for _ in 0..3 {
            mat_vec_q4k(&mut y_ref, &x, &w, n, d);
        }
        let t0 = Instant::now();
        for _ in 0..reps {
            mat_vec_q4k(&mut y_ref, &x, &w, n, d);
        }
        let prod = t0.elapsed().as_nanos() / reps;

        let bp = q4k_to_bitplanes_neon(&w, n, d);
        let mut y_lut = vec![0.0f32; n];
        for _ in 0..3 {
            mat_vec_q4k_lut_neon(&mut y_lut, &x, &bp);
        }
        let t1 = Instant::now();
        for _ in 0..reps {
            mat_vec_q4k_lut_neon(&mut y_lut, &x, &bp);
        }
        let lut = t1.elapsed().as_nanos() / reps;

        let (mut num, mut den) = (0.0f64, 0.0f64);
        for r in 0..n {
            let a = y_ref[r] as f64;
            num += (a - y_lut[r] as f64).powi(2);
            den += a * a;
        }
        let rel = (num / den).sqrt();
        println!(
            "[q4k-lut NEON] {n}x{d}: prod {:.1}us  lut {:.1}us  speedup {:.2}x  rel-L2 {:.2e}",
            prod as f64 / 1e3,
            lut as f64 / 1e3,
            prod as f64 / lut as f64,
            rel
        );
        assert!(rel < 0.06, "neon LUT rel-L2 too high: {rel:.3e}");
    }
}
